insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'hokkaido' and m.slug = 'sapporo'), 'hokkaido-sapporo-hearing-aid', '子どもの補聴器購入費等助成事業（札幌市）', '札幌市の独自制度で、身体障害者手帳の交付対象とならない軽度・中等度の難聴がある18歳未満の子どもについて、補聴器の購入・修理にかかる費用の一部を助成する事業です。助成基準額は障害者総合支援法の「高度難聴用耳かけ型補聴器」購入基準に準じ、実費との低い方が対象になる可能性があります。対象・金額・自己負担は公式での確認が必要です。', '札幌市にお住まいで、身体障害者手帳の対象にならない軽度・中等度の難聴があるお子さん（18歳未満）の補聴器の購入・修理費の一部を、市が助成する制度です。購入する前に区役所での申請が必要になる可能性があります。詳しい対象や金額は札幌市の公式ページでご確認ください。', 'subsidy', '申請日時点で満18歳未満かつ札幌市に住民登録があり、聴覚障がいに係る身体障害者手帳の交付を受けていない軽度・中等度難聴の子どもが対象とされています。いずれかの耳の平均聴力レベルがおおむね30デシベル以上で補聴器装用の効果が見込まれること等の要件があるとされ、詳細は公式で確認が必要です。', '助成基準額は障害者総合支援法の補装具費支給制度における「高度難聴用耳かけ型補聴器」の購入基準額に準じ、実際の購入（修理）費用と比較して低い方が対象になるとされています。市民税非課税世帯・生活保護受給世帯は自己負担なし、市民税課税世帯は助成基準額の1割が自己負担となるとされています。具体的な金額・自己負担割合は公式で確認してください。', '購入・修理の前に申請が必要とされています。期限の詳細は公式で確認してください。', '補聴器を購入・修理する前に、医療機関（補聴器相談医）を受診して意見書を作成し、補聴器販売店の見積書を用意したうえで、お住まいの区の区役所保健福祉課で申請する流れとされています。手続きの詳細は公式で確認してください。', '申請書、補聴器相談医の意見書、補聴器販売店の見積書などが必要とされています。最新の必要書類は公式でご確認ください。', FALSE, '札幌市保健福祉局障がい保健福祉部障がい福祉課在宅福祉係（申請は各区の区役所保健福祉課）', '011-211-2936', 'https://www.city.sapporo.jp/shogaifukushi/documents/nanchojihochoki.html', 'https://www.city.sapporo.jp/shogaifukushi/documents/nanchojihochoki.html', '子どもの補聴器購入費等を助成します／札幌市', '2026-06-27', 'high', ARRAY['benefitAmountText', 'targetPeople', 'requiredDocumentsText', 'applicationDeadlineText']::text[], '本ページは公式情報をもとにした概要です。対象・金額・自己負担・必要書類・期限などは変更される場合があるため、申請前に必ず札幌市の公式ページおよび各区の区役所保健福祉課でご確認ください。給付を確約するものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
insert into public.support_program_categories (support_program_id, category_id) select sp.id, c.id from public.support_programs sp, public.categories c where sp.slug = 'hokkaido-sapporo-hearing-aid' and c.slug = 'disability' on conflict do nothing;
insert into public.support_program_life_events (support_program_id, life_event_id) select sp.id, le.id from public.support_programs sp, public.life_events le where sp.slug = 'hokkaido-sapporo-hearing-aid' and le.slug = 'disability' on conflict do nothing;
insert into public.support_program_topics (support_program_id, support_topic_id) select sp.id, t.id from public.support_programs sp, public.support_topics t where sp.slug = 'hokkaido-sapporo-hearing-aid' and t.slug = 'hearing-aid' on conflict do nothing;
insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"hokkaido-sapporo-hearing-aid","status":"published","title":"子どもの補聴器購入費等助成事業（札幌市）","officialUrl":"https://www.city.sapporo.jp/shogaifukushi/documents/nanchojihochoki.html","topic":"hearing-aid"}'::jsonb, 'pilot:hokkaido-sapporo-hearing-aid:aG9ra2FpZG8tc2FwcG9yby1oZWFyaW5nLWFpZHzl' from public.support_programs sp where sp.slug='hokkaido-sapporo-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'miyagi' and m.slug = 'sendai'), 'miyagi-sendai-hearing-aid', '仙台市 軽・中等度難聴児の補聴器購入等の助成', '仙台市が実施する、身体障害者手帳の交付対象とならない軽・中等度の難聴のある18歳未満の児童を対象とした、補聴器の購入費等を助成する市独自制度です。聴こえの確保と言語発達の支援を目的としています。助成額・所得区分・対象要件は公式ページでの確認が必要です。', '仙台市では、身体障害者手帳の対象にならない軽度・中等度の難聴がある18歳未満のお子さんに、補聴器を買う費用の一部を助成しています。買う前の申請が必要で、医師の意見書や見積書を用意します。金額や条件は市の公式ページで確認してください。', 'subsidy', '仙台市内に住所がある18歳未満の方で、両耳とも平均聴力レベルが30dB以上あり、身体障害者手帳の交付対象とならず、医師が補聴器を必要と認めている方が対象とされています。具体的な該当可否は公式ページや窓口でご確認ください。', '購入費用と助成基準額を比較して低い方の額に3分の2を乗じた額（1,000円未満切捨て）が目安とされ、生活保護世帯・市民税非課税世帯は低い方の額の全額が助成されるとされています。基準額や上限など具体的な金額は公式ページでご確認ください。', NULL, '原則として補聴器の購入前に申請が必要です。申請書、医師が記載する難聴児補聴器等助成意見書、補聴器販売店が作成する見積書などを添えて、電子申請（せんだいオンライン申請サービス）または郵送で申請します。審査後に送付される助成券を購入時に提示する流れとされています。最新の手続きは公式ページでご確認ください。', '申請書、医師が記載する難聴児補聴器等助成意見書、補聴器販売店が作成する見積書、該当する場合は市町村民税課税証明書などが必要とされています。詳細は公式ページでご確認ください。', TRUE, '仙台市 健康福祉局 障害者総合支援センター', '022-771-6511', NULL, 'https://www.city.sendai.jp/shogai-jigyo/kurashi/kenkotofukushi/shogai/shien/shiencenter/sogoshien/shogaisha/jose.html', '軽・中等度難聴児の補聴器購入等の助成｜仙台市', '2026-06-27', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'onlineApplicationAvailable']::text[], '金額・対象・要件は変更される場合があります。最新の正確な情報は必ず仙台市の公式ページまたは窓口でご確認ください。高齢者（加齢性難聴）向けの市独自助成は本調査時点で公式に確認できませんでした。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
