insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"miyagi-sendai-hearing-aid","status":"published","title":"仙台市 軽・中等度難聴児の補聴器購入等の助成","officialUrl":"https://www.city.sendai.jp/shogai-jigyo/kurashi/kenkotofukushi/shogai/shien/shiencenter/sogoshien/shogaisha/jose.html","topic":"hearing-aid"}'::jsonb, 'pilot:miyagi-sendai-hearing-aid:bWl5YWdpLXNlbmRhaS1oZWFyaW5nLWFpZHzku5nl' from public.support_programs sp where sp.slug='miyagi-sendai-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'saitama' and m.slug = 'saitama'), 'saitama-saitama-hearing-aid', 'さいたま市 軽・中等度難聴児の補聴器の交付（補聴器購入費助成）', 'さいたま市が、身体障害者手帳の交付対象とならない軽・中等度の難聴のあるお子さんについて、言語の習得や教育・健全な発達を支えるため、補聴器の購入費用の一部を助成する市の制度です。対象や負担上限は所得などにより異なる可能性があるため、申請前に各区役所支援課への事前相談と公式での確認が必要です。なお、加齢性難聴の高齢者を対象とした市独自の補聴器購入費助成は、確認日時点では市公式ページで確認できませんでした。', '手帳の対象にならない軽い〜中くらいの難聴のお子さんの補聴器代を、さいたま市が一部助けてくれる制度です。買う前に区役所の支援課へ相談してください。費用の自己負担は原則1割ですが、家庭の所得によって上限や対象が変わることがあります。', 'subsidy', '対象となる可能性があるのは、さいたま市内に住所がある、満18歳に達する日以後の最初の3月31日までの難聴のあるお子さんで、両耳の聴力レベルが70デシベル未満（または片耳が70デシベル以上）で身体障害者手帳の交付対象とならず、補聴器の装用により言語習得などの効果が見込まれると判断される方とされています。所得などにより対象外となる場合があり、詳細は必ず公式で確認してください。', '公式情報によると、利用者負担は原則として購入費用の1割で、世帯の所得に応じた負担上限月額が設けられます。世帯の所得状況によっては助成の対象とならない場合があります。具体的な助成基準額・上限額は公式および各区役所支援課でご確認ください。', '公式に明示された申請期限は確認できませんでした。購入前の事前相談が前提となるため、詳細は各区役所支援課でご確認ください。', '公式情報によると、購入前にお住まいの区の区役所支援課（障害福祉係）への事前相談が必要で、その後、申請書・医師意見書（指定様式）・見積書・印鑑などを添えて区役所支援課へ申請します。購入済みの補聴器は助成の対象外となるため、必ず購入前に窓口へご相談ください。手続きの詳細は公式でご確認ください。', '公式情報によると、申請書、医師意見書（指定の様式）、見積書、印鑑などが必要とされています。最新の必要書類は各区役所支援課でご確認ください。', FALSE, '各区役所 支援課 障害福祉係', '区により異なります（例：西区 048-620-2662）。お住まいの区の支援課へお問い合わせください。', NULL, 'https://www.city.saitama.lg.jp/kosodate/shiritai/category10/p103567.html', '軽・中等度難聴児の補聴器の交付 - さいたま市', '2026-06-27', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'contactPhone', 'targetPeople']::text[], '本情報は2026-06-27時点でさいたま市公式サイトを確認してまとめた参考情報です。金額・対象・所得要件などは変更される場合があり、また高齢者（加齢性難聴）向けの市独自助成は公式で確認できませんでした。申請の可否や詳細は必ず公式・各区役所支援課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
insert into public.support_program_categories (support_program_id, category_id) select sp.id, c.id from public.support_programs sp, public.categories c where sp.slug = 'saitama-saitama-hearing-aid' and c.slug = 'disability' on conflict do nothing;
insert into public.support_program_life_events (support_program_id, life_event_id) select sp.id, le.id from public.support_programs sp, public.life_events le where sp.slug = 'saitama-saitama-hearing-aid' and le.slug = 'disability' on conflict do nothing;
