insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"saitama-saitama-hearing-aid","status":"published","title":"さいたま市 軽・中等度難聴児の補聴器の交付（補聴器購入費助成）","officialUrl":"https://www.city.saitama.lg.jp/kosodate/shiritai/category10/p103567.html","topic":"hearing-aid"}'::jsonb, 'pilot:saitama-saitama-hearing-aid:c2FpdGFtYS1zYWl0YW1hLWhlYXJpbmctYWlkfOOB' from public.support_programs sp where sp.slug='saitama-saitama-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kanagawa' and m.slug = 'yokohama'), 'kanagawa-yokohama-hearing-aid', '横浜市難聴者補聴器購入費助成事業', '横浜市が、難聴の改善を通じた認知症リスクの低減を目的に、身体障害者手帳（聴覚障害）の対象外となる軽度・中等度難聴の高齢者を中心に補聴器の購入費の一部を助成する市独自の制度です。市民税非課税世帯であることなど一定の要件があり、対象となるかは公式での確認が必要です。', '横浜市が、耳の聞こえにくさ（難聴）のある高齢の方などに、補聴器を買うお金の一部（上限2万円）を助成する制度です。市民税が非課税の世帯であることなどの条件があり、買う前にお医者さんの意見書が必要です。申請は郵送で、先着順のため早めの確認がおすすめです。対象になるかどうかは市の公式ページでご確認ください。', 'subsidy', '申請時点で横浜市に住民票がある50歳以上で、市民税非課税世帯に属し、両耳の聴力等について補聴器相談医から補聴器の必要性が証明され、身体障害者手帳（聴覚障害）が交付されていない（または交付対象外の）方などが対象となる可能性があります。詳しい要件は公式でご確認ください。', '助成上限は1人あたり20,000円（購入費と上限額のいずれか低い方）とされています。先着順・予算上限に達し次第終了となる場合があるため、最新の助成額・定員は公式でご確認ください。', '令和8年度は令和8年6月22日から令和9年2月26日（必着）と案内されています。先着300人・予算上限に達し次第終了とされ、年度により期間・定員が変わる可能性があるため公式でご確認ください。', '補聴器購入前に補聴器相談医のいる医療機関で医師意見書を作成してもらい、補聴器を購入した後、申請書類を郵送で提出する流れとされています。具体的な手続きは公式でご確認ください。', '助成金交付申請書兼実績報告書、医師意見書、補聴器購入日と金額の明細書（領収書等の写し）、補聴器装用前アンケートなどが必要とされています。最新の必要書類は公式でご確認ください。', FALSE, '横浜市医療局医療政策部医療政策課（補聴器購入費助成金受付担当）', '045-671-4872', 'https://www.city.yokohama.lg.jp/kenko-iryo-fukushi/kenko-iryo/iryo/seisaku/hochokijosei.html', 'https://www.city.yokohama.lg.jp/kenko-iryo-fukushi/kenko-iryo/iryo/seisaku/hochokijosei.html', '横浜市難聴者補聴器購入費助成事業（横浜市医療局）', '2026-06-27', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'targetPeople']::text[], '助成額・対象要件・申請期間・定員は年度や予算の状況により変わる可能性があります。最新かつ正確な情報は必ず横浜市の公式ページでご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
