insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"kanagawa-yokohama-hearing-aid","status":"published","title":"横浜市難聴者補聴器購入費助成事業","officialUrl":"https://www.city.yokohama.lg.jp/kenko-iryo-fukushi/kenko-iryo/iryo/seisaku/hochokijosei.html","topic":"hearing-aid"}'::jsonb, 'pilot:kanagawa-yokohama-hearing-aid:a2FuYWdhd2EteW9rb2hhbWEtaGVhcmluZy1haWR8' from public.support_programs sp where sp.slug='kanagawa-yokohama-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kanagawa' and m.slug = 'sagamihara'), 'kanagawa-sagamihara-hearing-aid', '相模原市 高齢者補聴器購入費助成（介護予防促進事業）', '相模原市が市独自の介護予防促進事業として実施する、高齢者の補聴器購入費の一部を助成する制度です。一定の要件を満たす65歳以上の高齢者を対象に、補聴器本体の購入費の一部（上限2万円）が助成される可能性があります。対象・金額・所得要件などの詳細は相模原市公式ページで確認してください。', '耳が聞こえにくくなった65歳以上の方が補聴器を買うとき、相模原市が費用の一部（上限2万円）を助成してくれる場合があります。市民税が非課税であることや、医師が補聴器が必要と認めることなどの条件があります。まずは地域包括支援センターや市の窓口に相談してください。', 'subsidy', '市内に住所を有し現に居住する65歳以上（年度途中に65歳に到達する転入者等を含む）で、市民税非課税（生活保護受給者を含む）、身体障害者手帳（聴覚障害）を所持していないかその対象外、医師により補聴器使用の必要性が認められる（原則として両耳30デシベル以上）、介護予防事業等への参加や補聴器装用前後のアンケート回答が可能、本助成をこれまでに受けたことがない、など市が定める要件を満たす方が対象となる可能性があります。詳しい対象条件は公式ページでご確認ください。', '補聴器本体購入費の一部を助成。医療機器認定を取得した補聴器本体の購入に要する費用と助成上限額（2万円）のいずれか低い額が助成されるとされていますが、金額・条件は変更されることがあるため公式ページでご確認ください。', '公式ページに明記なし。最新の受付状況・期限は相模原市にご確認ください。', '申請書（必要に応じて非課税証明書など）を、お住まいの地域の地域包括支援センターまたは各区の高齢・障害者相談課（福祉相談センター）へ、郵送または持参により提出して申請します。申請後に医師意見書の提出や、補聴器購入後の領収書提出などが必要となります。手続きの詳細・最新の流れは公式ページでご確認ください。', '申請書、（転入後間もない場合など必要に応じて）非課税証明書、医師意見書（申請後の段階で提出）、領収書（購入後）など。詳細は公式ページでご確認ください。', FALSE, '相模原市 高齢・障害者支援課（高齢支援班）', '042-769-9249', NULL, 'https://www.city.sagamihara.kanagawa.jp/kosodate/1026646/kaigo/1025658.html', '介護予防促進事業（高齢者補聴器購入費助成）｜相模原市', '2026-06-27', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は相模原市公式ページをもとに作成した概要です。対象条件・助成金額・申請方法は変更される場合があり、個別の支給可否は市の審査によります。必ず公式ページや市の窓口で最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
