insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'niigata' and m.slug = 'niigata'), 'niigata-niigata-hearing-aid', '新潟市 認知症予防のための補聴器購入費助成', '新潟市が独自に実施する、認知症予防のための補聴器購入費助成制度です。聴覚障がいによる身体障害者手帳の交付対象とならない聴力で、加齢などにより聞こえにくさを感じる中高年の方を対象に、補聴器の購入費の一部を助成する市の事業です（令和7年4月1日開始）。対象や助成額には市が定める要件があり、詳しくは公式ページでご確認ください。', '新潟市では、聞こえにくさを感じる中高年の方が補聴器を買うときの費用の一部（2分の1以内・上限25,000円）を助成しています。買う前の事前申請が必要で、対象には年齢や聴力などの条件があります。詳しくは市の窓口にご確認ください。', 'subsidy', '新潟市内に住所がある50歳以上74歳以下で、両耳の聴力レベルがそれぞれ40デシベル以上など、市が定める要件をすべて満たす方が対象となる可能性があります（身体障害者手帳の交付対象とならない聴力の方向け）。詳しい対象条件は公式ページでご確認ください。', '補聴器購入費の2分の1以内、上限25,000円（公式で確認。修理・部品交換・調整等の費用は対象外）。', '申請期限・受付期間は公式ページでご確認ください。事前申請制のため購入前の手続きが必要です。', '事前申請制です（購入後の申請はできません）。助成申請書・医師意見書・補聴器の見積書・納税証明書などを用意し、新潟市保健所健康増進課または各区役所の窓口で手続きします。必要書類や手続きの詳細は公式ページ・問い合わせ窓口でご確認ください。', '助成申請書、医師意見書（作成日から3か月以内）、補聴器の見積書、納税証明書（新潟市制度用、発行日から概ね1か月以内）など。最新の必要書類は公式ページでご確認ください。', FALSE, '新潟市 保健所健康増進課 健康づくり・歯科保健担当', '025-212-8166', NULL, 'https://www.city.niigata.lg.jp/iryo/kenko/yobo_kenshin/yobou-hotyouki/yobouhotyouki.html', '認知症予防のための補聴器購入費助成を実施しています（新潟市）', '2026-06-27', 'high', ARRAY['benefitAmountText', 'targetPeople', 'requiredDocumentsText', 'applicationDeadlineText']::text[], '本情報は新潟市公式ページ（確認日2026-06-27）に基づく概要です。対象要件・助成額・必要書類・受付状況は変更されることがあるため、申請前に必ず公式ページまたは問い合わせ窓口で最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
