insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'shizuoka' and m.slug = 'shizuoka'), 'shizuoka-shizuoka-hearing-aid', '静岡市 難聴高齢者補聴器購入費補助金', '静岡市が実施する、難聴のある高齢者の補聴器購入費を補助する市独自の制度です。市内在住の65歳以上で、補聴器相談医が装用を必要と診断した方などが対象となる可能性があり、補助上限は3万円（1回限り）とされています。市では別途、軽度・中等度難聴児向けの補聴器購入費助成も実施しています。対象要件・金額・申請期間は年度により変わる場合があるため、必ず静岡市の公式ページで最新情報をご確認ください。', '静岡市では、耳が聞こえにくい高齢者が補聴器を買うときの費用を一部補助しています。市内在住の65歳以上で、お医者さん（補聴器相談医）が補聴器が必要と判断した方などが対象になる可能性があり、補助は上限3万円（1回だけ）とされています。お子さん向けの別の助成もあります。対象や金額は年度で変わることがあるので、必ず静岡市の公式ページで確認してください。', 'subsidy', '静岡市内に住所がある65歳以上で、補聴器相談医が補聴器の装用を必要と診断し、身体障害者手帳（聴覚障害）の交付対象ではない方などが対象となる可能性があります。「聞こえに関する知識の動画視聴」またはアンケート回答、もしくは「聞こえの相談会」への参加等の要件があるとされ、詳しい対象条件は静岡市の公式ページでご確認ください。なお市では軽度・中等度難聴児向けの補聴器購入費助成も別制度として実施しています。', '補助上限3万円（交付は1回限り）とされています。補助対象経費や上限額は年度により変わる場合があるため、公式ページでご確認ください。', '年度ごとに申請期間が定められています（例として令和7年度／2026年度は2026年6月8日から2027年1月29日まで）。年度により変わる可能性があるため、公式ページで最新の期間をご確認ください。', '電子申請・郵送・窓口持参のいずれかで申請する方式とされています。診療情報提供書の写しや見積書、申請書兼同意書などの提出が求められる場合があります。申請期間や手続きの詳細は静岡市の公式ページでご確認ください。', '診療情報提供書（補聴器相談医の意見書）の写し、補聴器の見積書、申請書兼同意書などが必要とされ、購入後の実績報告時には納品書・領収書・介護予防活動報告書等の提出が求められる場合があります。詳細は公式ページでご確認ください。', TRUE, '静岡市 高齢者福祉課 いきいき長寿係', '054-221-1586', NULL, 'https://www.city.shizuoka.lg.jp/s2837/s012997.html', '静岡市難聴高齢者補聴器購入費補助制度について（静岡市）', '2026-06-27', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は静岡市公式ページの確認日時点の内容に基づく概括です。対象要件・補助金額・申請期間・必要書類は年度や制度改定により変わる場合があります。受給の可否は審査によって決まるため、申請にあたっては必ず静岡市の公式ページおよび担当課（高齢者福祉課 いきいき長寿係）で最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
