insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"shizuoka-shizuoka-hearing-aid","status":"published","title":"静岡市 難聴高齢者補聴器購入費補助金","officialUrl":"https://www.city.shizuoka.lg.jp/s2837/s012997.html","topic":"hearing-aid"}'::jsonb, 'pilot:shizuoka-shizuoka-hearing-aid:c2hpenVva2Etc2hpenVva2EtaGVhcmluZy1haWR8' from public.support_programs sp where sp.slug='shizuoka-shizuoka-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'shizuoka' and m.slug = 'hamamatsu'), 'shizuoka-hamamatsu-hearing-aid', '浜松市の補聴器購入費助成（高齢者補聴器装用検証事業・軽度中等度難聴児補聴器購入費助成）', '浜松市には、補聴器の購入費用を助成する市独自の制度があります。高齢者向けには「高齢者補聴器装用検証事業」があり、加齢性難聴と診断された一定の聴力レベルの方を対象に、補聴器本体購入金額の2分の1（上限3万円）を助成する可能性があります（定員・先着順）。あわせて、身体障害者手帳の交付対象とならない軽度・中等度難聴の児童向けに「軽度・中等度難聴児補聴器購入費助成事業」も用意されています。対象要件・金額・受付状況・年度は変わることがあるため、必ず浜松市の公式ページで最新情報をご確認ください。', '浜松市では、補聴器を買うときの費用の一部を市が助成してくれる制度があります。高齢の方向けは「高齢者補聴器装用検証事業」で、加齢による難聴と診断された一定の聞こえの方が対象になることがあり、補聴器本体の代金の半分（上限3万円）が助成される場合があります。定員があり先着順なので、年度の途中で受付が終わることもあります。子ども向けには、身体障害者手帳の対象にならない軽度・中等度の難聴の子どものための助成もあります。対象になるかどうかや金額は人によって違い、年度によって変わることもあるので、浜松市の公式ページで最新の内容を確認してください。', 'subsidy', '【高齢者補聴器装用検証事業】浜松市内在住で、誕生日が昭和36(1961)年4月1日以前、市税を完納し、聴覚障害者手帳の交付対象外で、補聴器相談医の受診により両耳の聴力レベルが各30dB以上70dB未満かつ加齢性難聴と診断され、これまで補聴器を購入したことがなく、効果検証アンケート（計3回）に協力できる方が対象となる可能性があります。【軽度・中等度難聴児補聴器購入費助成事業】浜松市内に住所がある18歳未満で、両耳の聴力レベルが原則30dB以上70dB未満、身体障害者手帳の交付対象とならない児童（世帯の市税完納・所得要件あり）が対象となる可能性があります。いずれも詳細な対象要件は浜松市の公式ページでご確認ください。', '高齢者補聴器装用検証事業では、補聴器本体購入金額の2分の1・上限3万円が助成される可能性があります（診察料・検査料・修理・調整・送料・付属品等は対象外）。軽度・中等度難聴児補聴器購入費助成事業では、算定基礎額（購入費用と別表の基準額の低い方）の3分の2が助成される可能性があります。金額・上限・割合は変更されることがあるため、公式で確認してください。', '高齢者補聴器装用検証事業は年度ごとに受付期間・定員（先着100人）が設定されます（例：令和8(2026)年度は4月15日から受付）。先着順のため定員に達し次第終了し、年度途中で受付が締め切られる場合があります（公式ページ上で『定員間近』と案内される時期もあります）。最新の受付状況・期限は必ず浜松市公式でご確認ください。', '【高齢者補聴器装用検証事業】医師意見書・見積書・装用前アンケートを準備し、マイナンバーカードを用いて浜松市のオンライン申請から申請します（補聴器の購入は申請後）。受付は年度ごとに期間・定員（先着順）が設けられます。【軽度・中等度難聴児補聴器購入費助成事業】購入前に社会福祉課（障害担当）窓口で相談のうえ、必要書類を添えて申請します（購入後の申請は対象外となる可能性があります）。具体的な手続きは公式ページで確認してください。', '高齢者補聴器装用検証事業では、マイナンバーカード（署名用電子証明書暗証番号）、補聴器相談医による医師意見書（画像データ）、補聴器の見積書、装用前アンケートが必要とされています。難聴児向けは交付申請書・見積書等が必要です。詳細は公式の案内・要綱で確認してください。', TRUE, '浜松市役所 健康福祉部 高齢者福祉課（高齢者向け：053-457-2789）／障害者政策課・障害者支援課（難聴児向け：053-457-2212）', '053-457-2789', 'https://www.city.hamamatsu.shizuoka.jp/kourei/welfare/elderly/kareihotyoki.html', 'https://www.city.hamamatsu.shizuoka.jp/kourei/welfare/elderly/kareihotyoki.html', '高齢者補聴器装用検証事業／浜松市', '2026-06-27', 'high', ARRAY['applicationDeadlineText（年度ごとの受付期間・定員の最新の受付状況）', '所得制限の詳細', '難聴児向け制度の助成額・基準額の最新値']::text[], '本内容は浜松市公式ページ（2026-06-27確認）を基にした概要です。対象要件・助成額・所得制限・受付期間・定員は変更される場合があり、受給を確約するものではありません。高齢者向け制度は先着順・定員制のため、年度途中で受付終了となることがあります。申請可否や金額は浜松市の審査により決まります。最新かつ正確な情報は必ず浜松市の公式ページ・担当課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
