insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"shizuoka-hamamatsu-hearing-aid","status":"published","title":"浜松市の補聴器購入費助成（高齢者補聴器装用検証事業・軽度中等度難聴児補聴器購入費助成）","officialUrl":"https://www.city.hamamatsu.shizuoka.jp/kourei/welfare/elderly/kareihotyoki.html","topic":"hearing-aid"}'::jsonb, 'pilot:shizuoka-hamamatsu-hearing-aid:c2hpenVva2EtaGFtYW1hdHN1LWhlYXJpbmctYWlk' from public.support_programs sp where sp.slug='shizuoka-hamamatsu-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'aichi' and m.slug = 'nagoya'), 'aichi-nagoya-hearing-aid', '名古屋市軽度・中等度難聴児補聴器購入費助成事業', '名古屋市が実施する市独自の補聴器購入費助成制度です。身体障害者手帳の交付対象とならない軽度・中等度の難聴のあるお子さんが補聴器を購入する際の費用の一部を助成する制度として、名古屋市公式サイトで案内されています。対象や助成額・所得区分などの詳細は公式ページでご確認ください。', '名古屋市では、身体障害者手帳の対象にならない軽度・中等度の難聴のお子さん（18歳以下）が補聴器を買うときに、費用の一部を市が助成する制度があります。対象や金額には条件があるため、申請前に名古屋市の公式ページや子ども福祉課（052-972-2520）でご確認ください。', 'subsidy', '名古屋市内に住所があり、聴力レベルが原則として30デシベル以上で身体障害者手帳の交付対象とならず、医師に補聴器の装用が必要と診断された18歳以下の児童が対象となる可能性があります。具体的な対象要件は名古屋市公式ページでご確認ください。', '基準額の範囲内で購入費の10分の9を助成（生活保護世帯・市民税非課税世帯は基準額の全額を助成）とされています。金額・上限・区分の詳細は公式で確認が必要です。', '公式ページに具体的な申請期限の記載は確認できませんでした。詳細は窓口へご確認ください。', '申請書・医師意見書・補聴器取扱業者の見積書を用意し、子ども福祉課へ電子申請または郵送等で申請する流れが公式に案内されています。最新の申請手順・提出先は公式ページでご確認ください。', '申請書、医師意見書、補聴器取扱業者が作成した見積書が必要とされています。', TRUE, '名古屋市 子ども青少年局 子育て支援部 子ども福祉課 子ども発達支援担当', '052-972-2520', 'https://www.city.nagoya.jp/kodomoseishonen/page/0000053655.html', 'https://www.city.nagoya.jp/kenkofukushi/shougaisha/1011194/1011196.html', '名古屋市軽度・中等度難聴児補聴器購入費助成事業｜名古屋市公式ウェブサイト', '2026-06-27', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'targetPeople', 'onlineApplicationAvailable']::text[], '本情報は名古屋市公式サイトの掲載内容を要約したものです。対象要件・助成額・申請手続は変更される場合があるため、申請前に必ず公式ページおよび窓口でご確認ください。高齢者（加齢性難聴）向けの市独自助成は、確認日時点では名古屋市で確認できませんでした。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
insert into public.support_program_categories (support_program_id, category_id) select sp.id, c.id from public.support_programs sp, public.categories c where sp.slug = 'aichi-nagoya-hearing-aid' and c.slug = 'disability' on conflict do nothing;
insert into public.support_program_life_events (support_program_id, life_event_id) select sp.id, le.id from public.support_programs sp, public.life_events le where sp.slug = 'aichi-nagoya-hearing-aid' and le.slug = 'disability' on conflict do nothing;
insert into public.support_program_topics (support_program_id, support_topic_id) select sp.id, t.id from public.support_programs sp, public.support_topics t where sp.slug = 'aichi-nagoya-hearing-aid' and t.slug = 'hearing-aid' on conflict do nothing;
insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"aichi-nagoya-hearing-aid","status":"published","title":"名古屋市軽度・中等度難聴児補聴器購入費助成事業","officialUrl":"https://www.city.nagoya.jp/kenkofukushi/shougaisha/1011194/1011196.html","topic":"hearing-aid"}'::jsonb, 'pilot:aichi-nagoya-hearing-aid:YWljaGktbmFnb3lhLWhlYXJpbmctYWlkfOWQjeWP' from public.support_programs sp where sp.slug='aichi-nagoya-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kyoto' and m.slug = 'kyoto'), 'kyoto-kyoto-hearing-aid', '京都市難聴児補聴器購入費助成事業', '京都市が実施する、身体障害者手帳の交付対象とならない18歳未満の難聴児を対象とした補聴器購入費の助成制度です。教育・言語訓練・生活適応訓練の促進を目的に、補聴器の購入費用の一部を助成します。助成額は補聴器1個あたり4万円を上限とし、両耳分が必要と認められる場合は2個まで対象となる可能性があります。詳細・最新の要件は京都市公式ページでご確認ください。', '京都市にお住まいで、身体障害者手帳の対象にはならないけれど耳の聞こえにくさがある18歳未満のお子さんが、補聴器を買うときの費用の一部（補聴器1個あたり最大4万円）を京都市が助成する制度です。お医者さんが補聴器を必要と認めることなどが条件で、申請には医師の意見書やお店の見積書が必要です。詳しい条件や手続きは京都市の公式ページや担当課でご確認ください。', 'subsidy', '京都市内に住所があり、身体障害者手帳の交付対象とならない18歳未満の難聴児で、医師が補聴器の装用を必要と認めた方が対象となる可能性があります。対象の詳細や聴力等の要件は京都市公式ページでご確認ください。', '補聴器1個あたり4万円を上限として購入費用の一部を助成（補聴器の価格が上限額より低い場合はその価格が上限）。両耳分が必要と認められる場合は2個まで助成の対象となる可能性があります。前回の助成を受けてから5年未満は再度の助成を受けられない旨が案内されています。金額の詳細は公式でご確認ください。', '公式ページに明確な申請期限の記載は確認できませんでした。詳細は京都市の担当課にご確認ください。', '京都市難聴児補聴器購入費助成申請書に、医師意見書および登録事業者の見積書を添付して、京都市（市長）に提出する方法が案内されています。具体的な様式・提出先・手続きの詳細は、京都市の担当課または公式ページでご確認ください。', '申請書、医師意見書、登録事業者の見積書など。医師意見書は身体障害者福祉法に基づく指定医等が作成する旨が案内されています。必要書類の詳細は京都市公式ページでご確認ください。', FALSE, '京都市 子ども若者はぐくみ局 子ども若者未来部 子ども家庭支援課', '075-222-3939', 'https://www.city.kyoto.lg.jp/hagukumi/page/0000229104.html', 'https://www.city.kyoto.lg.jp/hagukumi/page/0000229104.html', '京都市：京都市難聴児補聴器購入費助成事業実施要綱', '2026-06-27', 'high', ARRAY['applicationDeadlineText', '所得制限の有無・現状']::text[], '本内容は京都市公式ページをもとにした概要です。対象・金額・所得制限・手続き等は変更される場合があり、また細部は公式で要確認です。なお、高齢者（加齢性難聴）や成人障害者一般を対象とした京都市独自の補聴器購入費助成は、本調査時点では公式に確認できませんでした（身体障害者手帳に該当する場合は障害者総合支援法の補装具費支給制度の対象となる可能性があります）。最新かつ正確な情報は必ず京都市公式ページでご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
