insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"kyoto-kyoto-hearing-aid","status":"published","title":"京都市難聴児補聴器購入費助成事業","officialUrl":"https://www.city.kyoto.lg.jp/hagukumi/page/0000229104.html","topic":"hearing-aid"}'::jsonb, 'pilot:kyoto-kyoto-hearing-aid:a3lvdG8ta3lvdG8taGVhcmluZy1haWR85Lqs6YO9' from public.support_programs sp where sp.slug='kyoto-kyoto-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'osaka' and m.slug = 'osaka'), 'osaka-osaka-hearing-aid', '大阪市難聴高齢者補聴器購入費助成事業', '大阪市が実施する、65歳以上で軽度・中等度の難聴がある高齢者を対象に、補聴器の購入費用の一部（公式案内では1回の購入で25,000円を上限）を助成する市独自の制度です。身体障害者手帳（聴覚）の交付対象とならない方を念頭に置いた、介護予防を目的とする事業とされています。対象要件・助成額・運用は年度や個別事情により異なる場合があるため、必ず大阪市公式ページで最新の内容をご確認ください。', '大阪市には、65歳以上で耳の聞こえにくさ（軽度・中等度の難聴）がある方が補聴器を買うときに、その費用の一部を市が助成してくれる制度があります。公式の案内では1回の購入につき25,000円までが目安です。買う前の申請が必要で、郵送・窓口・大阪市行政オンラインシステムから申し込めます。お医者さん（補聴器相談医）の意見書などが必要です。条件や金額は変わることがあるので、申し込む前に大阪市の公式ページや担当課で確認しましょう。', 'subsidy', '大阪市内に住所があり、申請時点で65歳以上の方で、両耳の聴力レベルがそれぞれ30デシベル以上70デシベル未満であり、補聴器相談医が補聴器の必要性を認めた方などが対象とされています。身体障害者手帳（聴覚機能の障がいに係るもの）の交付対象者ではないこと、過去に本助成を受けていないこと、介護予防活動等を行うことなどの条件が公式案内に示されています。対象に該当するかは大阪市公式ページおよび窓口でご確認ください。', '公式案内では、1回の購入につき25,000円を上限に補聴器の購入費用の一部を助成（補聴器購入費が対象とされ、助成は過去に本助成を受けていない方が対象です）。金額・条件は変更される場合があるため公式ページで最新情報を確認してください。', '助成対象者の決定通知書を受け取った日の翌日から6か月以内に費用請求に係る書類を提出する必要があるとされています（必着）。なお購入前の申請が必要です。詳細は公式ページでご確認ください。', '申請に必要な書類を用意のうえ、大阪市福祉局高齢者施策部地域包括ケア推進課へ郵送または窓口持参で申請するほか、「大阪市行政オンラインシステム」でのオンライン申請も可能とされています。助成を受けようとする補聴器を購入する前に申請する必要があるとされています。詳細・最新の手続きは公式ページでご確認ください。', '公式案内では、申請書（様式第1号）、補聴器相談医が作成する医師意見書（様式第2号）、認定補聴器専門店または認定補聴器技能者による補聴器見積書などが必要とされています。最新の必要書類は公式ページ・窓口でご確認ください。', TRUE, '大阪市福祉局高齢者施策部地域包括ケア推進課', '06-6208-9957', NULL, 'https://www.city.osaka.lg.jp/fukushi/page/0000648793.html', '大阪市：65歳以上の軽度・中等度の難聴の高齢者の方を対象に補聴器購入費用の一部を助成します。', '2026-06-27', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は大阪市公式ページ（確認日2026-06-27）に基づく概要です。助成額・対象要件・所得要件・申請手続きは年度や個別事情により変わる場合があります。受給の可否は審査によって決まり、申請すれば必ず助成されるものではありません。最新かつ正確な情報は必ず大阪市公式ページおよび担当課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
