insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"osaka-osaka-hearing-aid","status":"published","title":"大阪市難聴高齢者補聴器購入費助成事業","officialUrl":"https://www.city.osaka.lg.jp/fukushi/page/0000648793.html","topic":"hearing-aid"}'::jsonb, 'pilot:osaka-osaka-hearing-aid:b3Nha2Etb3Nha2EtaGVhcmluZy1haWR85aSn6Ziq' from public.support_programs sp where sp.slug='osaka-osaka-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'hyogo' and m.slug = 'kobe'), 'hyogo-kobe-hearing-aid', '神戸市 軽度・中等度難聴児補聴器購入費等助成事業', '神戸市が実施する市独自の補聴器購入費助成制度です。身体障害者手帳の交付対象とならない軽度・中等度の難聴児が補聴器を購入する際の費用の一部を助成する可能性があります。対象や助成額の詳細は神戸市公式ページでご確認ください。', '神戸市では、身体障害者手帳の対象にならない程度の難聴のお子さんが補聴器を買うときに、費用の一部を市が助成する制度があります。対象になるかどうか、いくら助成されるかは、購入の前に区役所の保健福祉課に確認することをおすすめします。', 'subsidy', '18歳に達する日以後の最初の3月31日までの間にある児童で、両耳の聴力レベルがおおむね30dB以上70dB未満など、身体障害者手帳の交付対象とならない軽度・中等度の難聴児が対象となる可能性があります。保護者が神戸市に居住していることなどの要件があるとされます。詳細な対象条件は公式でご確認ください。', '助成上限の例として、ポケット型・耳かけ型などは40,000円、骨導式眼鏡型・オーダーメイド耳穴型・補聴システムは100,000円とされる可能性があります（実際の購入価格がこれを下回る場合はその額）。最新の助成額は神戸市公式でご確認ください。', '申請期限・申請時期の詳細は神戸市公式ページまたは区役所窓口でご確認ください。', '申請は、お住まいの区役所（北須磨支所を含む）の保健福祉課で行うとされています。補聴器を購入する前の相談・申請が必要となる可能性があるため、購入前に窓口でご確認ください。', '医師の意見書（補聴器の必要性の判定）、見積書、所定の申請書類などが必要となる可能性があります。必要書類は購入前に区役所保健福祉課でご確認ください。', FALSE, 'お住まいの区役所 保健福祉課（北須磨支所を含む）／神戸市福祉局障害者支援課', NULL, 'https://www.city.kobe.lg.jp/a95295/kenko/handicap/zaitakufukushi/kigu/nanchojihochoki.html', 'https://www.city.kobe.lg.jp/a95295/kenko/handicap/zaitakufukushi/kigu/nanchojihochoki.html', '軽度・中等度難聴児補聴器購入費等助成事業 - 神戸市', '2026-06-27', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText', 'contactPhone', '高齢者（加齢性難聴）向け制度の有無', '所得制限の有無・水準']::text[], '本情報は2026-06-27時点で神戸市公式ページをもとに作成した概要です。対象条件・助成額・所得要件・申請方法は変更される場合があり、また個別の支給の可否は審査により判断されます。必ず神戸市公式ページおよび区役所窓口で最新情報をご確認ください。なお、高齢者（加齢性難聴）向けの補聴器購入費助成については、本調査時点で神戸市公式の独立した制度ページは確認できませんでした。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
