insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"hyogo-kobe-hearing-aid","status":"published","title":"神戸市 軽度・中等度難聴児補聴器購入費等助成事業","officialUrl":"https://www.city.kobe.lg.jp/a95295/kenko/handicap/zaitakufukushi/kigu/nanchojihochoki.html","topic":"hearing-aid"}'::jsonb, 'pilot:hyogo-kobe-hearing-aid:aHlvZ28ta29iZS1oZWFyaW5nLWFpZHznpZ7miLjl' from public.support_programs sp where sp.slug='hyogo-kobe-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'okayama' and m.slug = 'okayama'), 'okayama-okayama-hearing-aid', '難聴高齢者補聴器購入費助成事業（岡山市）', '岡山市が実施する高齢者向けの補聴器購入費助成制度です。聞こえづらさのある高齢者の適切な補聴器装用を支援し、コミュニケーション能力の維持・向上やフレイル予防、社会参加の促進を図ることを目的としています。一定の要件（年齢・市民税非課税世帯・聴力など）を満たし、身体障害者手帳の交付対象とならない方が対象となる可能性があります。助成額は購入費の2分の1以内（上限25,000円）とされていますが、対象要件・金額の詳細は岡山市の公式ページでご確認ください。', '岡山市が65歳以上の方向けに行っている、補聴器を買うときの費用の一部を助成する制度です。市民税非課税世帯であることや、両耳の聞こえの状態など一定の条件があり、身体障害者手帳の対象にならない方が対象になる可能性があります。助成は購入費の半分まで（上限25,000円）とされています。必ず補聴器を買う前に市の窓口で申請する必要があります。条件や金額の詳しい内容は岡山市の公式ページで確認してください。', 'subsidy', '岡山市に住民登録のある65歳以上で、市民税非課税世帯に属し、原則として両耳の聴力レベルがいずれも40dB以上、かつ身体障害者手帳（聴覚障害）の交付対象とならない方が対象となる可能性があります。耳鼻咽喉科医により補聴器の必要性が認められること、また過去5年以内に本事業の助成金交付決定を受けていないことも要件とされています。詳しい対象要件は公式でご確認ください。', '補聴器購入費の2分の1以内（上限25,000円）とされています。補聴器1台分の本体および付属品購入費が対象です。金額・上限は岡山市の公式ページでご確認ください。', '申請期限についてはページ上に明記がありません。補聴器の購入前に申請する必要があるため、最新の取扱いは岡山市の公式ページや担当課でご確認ください。', '補聴器を購入する前に、もよりの福祉事務所または各支所総務民生課の窓口で申請します。申請後、医師意見書様式を持参して耳鼻咽喉科を受診し、認定補聴器専門店で見積もりを取得し、交付決定後に補聴器を購入する流れとされています。購入後の申請は対象外とされているため、必ず購入前に申請手続きを行う必要があります。詳細・最新の手続きは岡山市の公式ページでご確認ください。', '本人確認書類、申請書、医師意見書、補聴器の見積、実績報告及び請求書兼委任状などが必要とされています。必要書類の詳細は岡山市の公式ページでご確認ください。', FALSE, '岡山市 保健福祉局高齢福祉部高齢者福祉課 在宅支援係', '086-803-1230', 'https://www.city.okayama.jp/kurashi/0000061124.html', 'https://www.city.okayama.jp/kurashi/0000061124.html', '難聴高齢者補聴器購入費助成事業 | 岡山市', '2026-06-27', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本ページは岡山市の公式情報をもとに作成した要約です。対象要件・助成額・申請手続きは変更される場合があるため、申請前に必ず岡山市の公式ページおよび担当課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
