insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"okayama-okayama-hearing-aid","status":"published","title":"難聴高齢者補聴器購入費助成事業（岡山市）","officialUrl":"https://www.city.okayama.jp/kurashi/0000061124.html","topic":"hearing-aid"}'::jsonb, 'pilot:okayama-okayama-hearing-aid:b2theWFtYS1va2F5YW1hLWhlYXJpbmctYWlkfOmb' from public.support_programs sp where sp.slug='okayama-okayama-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'hiroshima' and m.slug = 'hiroshima'), 'hiroshima-hiroshima-hearing-aid', '広島市 難聴児補聴器購入費助成事業（補聴器購入費の助成）', '広島市が実施する補聴器購入費の助成制度です。公式サイトでは、身体障害者手帳の交付対象とならない軽度・中等度の難聴児（18歳未満）を対象に、補聴器購入費の一部を助成する「難聴児補聴器購入費助成事業」が案内されています。あわせて、聴覚障害の身体障害者手帳をお持ちの方等には別途「補装具費支給制度」による支給があるとされています。なお、いわゆる高齢者（手帳のない65歳以上）向けの補聴器購入費助成については、確認日時点で公式の制度ページが見当たりませんでした。対象・金額・申請方法は変更されることがあるため、必ず広島市公式サイトや障害福祉課・お住まいの区の福祉課でご確認ください。', '広島市には、補聴器を買うときの費用を助ける制度があります。公式サイトで案内されているのは、おもに耳の聞こえにくい子ども（18歳未満で身体障害者手帳の対象にならない軽度・中等度の難聴児）向けの助成です。購入費と市が決めた基準価格の少ないほうの3分の2が助成されます。買う前に区の福祉課へ申請が必要です。手帳をお持ちの方は別の補装具費支給制度の対象になることがあります。お年寄り（手帳のない高齢者）向けの補聴器助成は、調べた時点では公式の案内が見つかりませんでした。対象や金額は変わることがあるので、必ず広島市の公式ページや障害福祉課で確認してください。', 'subsidy', '広島市内に住所がある18歳未満で、身体障害者手帳の交付対象とならない軽度・中等度の難聴児が対象となる可能性があります（公式では両耳の聴力レベルがいずれも30デシベル以上等の要件が示されています）。聴覚障害の身体障害者手帳をお持ちの方等は補装具費支給制度の対象となる場合があります。対象要件は変更され得るため、必ず広島市公式で確認してください。', '公式によると、難聴児補聴器購入費助成事業では、補聴器の購入費と市が定める基準価格を比較して少ない方の額の3分の2が助成されます（例：軽度・中等度難聴用耳かけ型は基準価格55,900円・助成額37,200円とされています）。金額は改定され得るため、最新額は公式でご確認ください。', '公式ページに明確な通年・期限の記載は確認できませんでした。補聴器購入前の申請が必要とされている点に注意し、詳細は広島市にご確認ください。', '公式によると、難聴児補聴器購入費助成事業は、申請書（様式第1号）・医師の意見書・補聴器の見積書・対象児童の聴力レベル証明書等を添えて、お住まいの区の福祉課に申請します。購入後の申請は対象外とされ、令和8年（2026年）4月から助成方法が代理受領方式に変更される旨が案内されています。詳細・最新の手続きは広島市公式や障害福祉課でご確認ください。', '公式によると、申請書（様式第1号）、医師の意見書、補聴器の見積書、対象児童の聴力レベル証明書などが必要とされています。最新の必要書類は広島市公式でご確認ください。', FALSE, '広島市 健康福祉局障害福祉部 障害福祉課（またはお住まいの区の福祉課）', '082-504-2147', 'https://www.city.hiroshima.lg.jp/living/fukushi-kaigo/1014921/1006076/1006093/1036823.html', 'https://www.city.hiroshima.lg.jp/site/syougaijiritu01/18646.html', '難聴児補聴器購入費助成事業｜広島市公式ウェブサイト', '2026-06-27', 'high', ARRAY['targetPeople', 'benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', '高齢者（手帳のない65歳以上）向けの市独自の補聴器購入費助成の有無（確認日時点で公式に制度ページを確認できず）']::text[], '本内容は広島市公式サイトの情報をもとにした概況です。対象・金額・申請方法・期限は変更される場合があり、個別の受給可否を保証するものではありません。最新の正確な情報と手続きは広島市公式ページおよび障害福祉課・お住まいの区の福祉課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
