insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"hiroshima-hiroshima-hearing-aid","status":"published","title":"広島市 難聴児補聴器購入費助成事業（補聴器購入費の助成）","officialUrl":"https://www.city.hiroshima.lg.jp/site/syougaijiritu01/18646.html","topic":"hearing-aid"}'::jsonb, 'pilot:hiroshima-hiroshima-hearing-aid:aGlyb3NoaW1hLWhpcm9zaGltYS1oZWFyaW5nLWFp' from public.support_programs sp where sp.slug='hiroshima-hiroshima-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'fukuoka' and m.slug = 'fukuoka'), 'fukuoka-fukuoka-hearing-aid', '福岡市 難聴児への補聴器購入助成', '福岡市が実施する、身体障害者手帳（聴覚障がい）の対象とはならないが補聴器の装着が必要な18歳未満の難聴児を対象とした、補聴器購入費の助成制度です。基準額は片耳50,000円で、原則として費用の1割が自己負担となり、世帯の所得状況に応じて負担上限が設定されます。申請には、身体障害者福祉法第15条に規定する指定医（聴覚障がい）による意見書などが必要で、補聴器の購入前に申請する必要があります。対象要件・助成額・所得に応じた負担上限などの詳細は、福岡市の公式案内および居住区の区役所窓口でご確認ください。', '福岡市では、身体障害者手帳の対象にはならないけれど補聴器が必要な18歳未満のお子さんのために、補聴器の購入費を助成する制度があります。助成の基準額は片耳5万円で、原則として費用の1割が自己負担です（所得に応じて負担の上限があります）。申請はお住まいの区役所の窓口で、補聴器を買う前に行う必要があり、指定医の意見書などが必要です。対象になる聴力の条件や手続きの詳細は、福岡市の公式案内や区役所の窓口で確認してください。', 'subsidy', '福岡市内に住所を有し、身体障害者手帳（聴覚障がい）の対象とならない18歳未満の児童で、身体障害者福祉法第15条に規定する指定医（聴覚障がい）から補聴器の装着が必要と認められ、かつ聴力レベルが四分法で原則として両耳とも平均30デシベル以上の者（意見書によって必要性が認められた場合はこの限りではありません）。詳細な対象要件は公式でご確認ください。', '基準額は片耳あたり50,000円。原則として用具給付に要する費用の1割が自己負担となり、世帯の所得状況に応じて一定の負担上限が設定されます。具体的な金額・負担上限は公式の案内および区役所窓口でご確認ください。', '原則として補聴器の購入前に申請が必要です（購入後の申請は対象外となる場合があります）。詳細は公式でご確認ください。', '補聴器の購入前に、お住まいの区役所の福祉・介護保険課障がい者福祉係の窓口で申請します。申請には、申請書（印鑑）、身体障害者福祉法第15条指定医（聴覚障がい）が作成した意見書、福岡市と補装具費代理受領契約を結んでいる業者からの見積書が必要です。詳しい手続きは公式の案内および居住区の区役所窓口でご確認ください。', '申請書（印鑑、区役所で交付）、身体障害者福祉法第15条指定医（聴覚障がい）が作成した意見書（区役所で様式交付）、福岡市と補装具費代理受領契約を結んでいる業者からの見積書（詳細は区役所窓口で要確認）', FALSE, '福岡市福祉局障がい在宅福祉課（および居住区の区役所 福祉・介護保険課 障がい者福祉係）', '092-711-4985', 'https://www.city.fukuoka.lg.jp/fukushi/syougaisyashien/health/nitijyoseikatuyougu.html', 'https://www.city.fukuoka.lg.jp/fukushi/syougaisyashien/health/nitijyoseikatuyougu.html', '日常生活用具の給付（難聴児用補聴器）／難聴児への補聴器購入助成について（ご案内） - 福岡市', '2026-06-27', 'high', '{}'::text[], '対象要件・助成額・所得に応じた負担上限・申請手続きは変更される場合があります。最新かつ正確な内容は、必ず福岡市の公式案内および居住区の区役所窓口でご確認ください。本情報は受給を確約するものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
