insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot hearing-aid import', '{"slug":"fukuoka-fukuoka-hearing-aid","status":"published","title":"福岡市 難聴児への補聴器購入助成","officialUrl":"https://www.city.fukuoka.lg.jp/fukushi/syougaisyashien/health/nitijyoseikatuyougu.html","topic":"hearing-aid"}'::jsonb, 'pilot:fukuoka-fukuoka-hearing-aid:ZnVrdW9rYS1mdWt1b2thLWhlYXJpbmctYWlkfOem' from public.support_programs sp where sp.slug='fukuoka-fukuoka-hearing-aid' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kumamoto' and m.slug = 'kumamoto'), 'kumamoto-kumamoto-hearing-aid', '熊本市難聴高齢者介護予防促進事業（高齢者補聴器購入費助成）', '熊本市が、聞こえづらさから日常生活に不安を感じている高齢者を対象に、補聴器の購入費用の一部を助成する市の事業です。身体障害者手帳（聴覚障害）の交付対象とならない、医師により補聴器の効果が認められた市民税非課税世帯等の高齢者が対象となる可能性があります。助成額や自己負担などの詳細は公式ページや各区福祉課でご確認ください。', '耳が聞こえにくくなった高齢の方が補聴器を買うとき、熊本市がその費用の一部を助成してくれる制度です。市民税非課税世帯などで、障害者手帳の対象にならない方が対象になる場合があります。まず地域包括支援センターに相談し、耳鼻科を受診してから区役所の福祉課に申し込みます。', 'subsidy', '熊本市に住民登録があり、医師により補聴器の効果が認められた65歳以上の方で、市民税非課税世帯または生活保護受給中、かつ身体障害者手帳（聴覚障害）の交付対象とならない方が対象となる可能性があります。アンケート回答や介護予防事業への参加が要件に含まれます。詳しい要件は公式情報でご確認ください。', NULL, '令和8年6月1日より受付開始とされています。終了日等は公式ページでご確認ください。', '地域包括支援センターへの相談後、耳鼻咽喉科を受診し、認定補聴器技能者が在籍する販売店で見積書を作成のうえ、お住まいの区の区役所福祉課へ申請します（高齢福祉課の審査・交付決定後に補聴器を購入）。必要書類として申請書・医師意見書・見積書が案内されています。詳細・最新の手続きは公式ページや各区福祉課でご確認ください。', '申請書、医師意見書、見積書（公式案内による。詳細は各区福祉課で確認）', FALSE, '各区役所福祉課／熊本市高齢福祉課（熊本市コールセンター）', '096-334-1500', NULL, 'https://www.city.kumamoto.jp/kiji00370685/index.html', '熊本市難聴高齢者介護予防促進事業（高齢者補聴器購入費助成） / 熊本市公式サイト', '2026-06-27', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'onlineApplicationAvailable']::text[], '対象要件・助成額・申請期限は変更される場合があります。最新かつ正確な情報は必ず熊本市公式ページまたは各区役所福祉課でご確認ください。本サイトは申請の代行は行いません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
