insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.sapporo.jp/shogaifukushi/documents/nanchojihochoki.html', '敵対的検証: program.officialUrl を WebFetch で取得し全項目を点検。(a)到達=正常表示(404/エラーなし)。(b)許可ホスト=www.city.sapporo.jp は city.* パターンに合致、FAQ専用ドメインではない。(c)当該市・当該制度=ページタイトル「子どもの補聴器購入費等を助成します／札幌市」、制度名「札幌市子どもの補聴器購入費等助成事業」で札幌市公式・別市別区でない。(d)現行=更新日2026年3月31日、受付終了表記なし。(e)国/都道府県制度の誤認なし=札幌市独自の障害福祉系制度。(f)対象の部分→全体化なし=タイトル・対象とも「満18歳未満かつ手帳非該当の軽度〜中等度難聴児」に正しく限定。(g)複数制度の混在なし=単一制度。(h)断定なし=金額・対象・必要書類・期限は概括＋「公式で確認」。公式の数値も一致確認(満18歳未満／平均聴力30dB以上／聴覚の身体障害者手帳の交付を受けていないこと／市民税非課税・生保=自己負担0円・市民税課税=助成基準額の1割／窓口=お住まいの区の区役所保健福祉課／所管=保健福祉局障がい保健福祉部障が' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='hokkaido' and m.slug='sapporo' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.sendai.jp/shogai-jigyo/kurashi/kenkotofukushi/shogai/shien/shiencenter/sogoshien/shogaisha/jose.html', '敵対検証実施。(a)到達: officialUrl を WebFetch + curl で確認、HTTP 200・クロスホストリダイレクトなし。(b)許可ホスト: www.city.sendai.jp は city.* 系の正規公式ホスト。一次調査が除外した guide.callcenter.city.sendai.jp（FAQ専用ドメイン）と smart-hojokin.jp（公式リンク先は名取市であり仙台市でない）の判断は妥当。(c)当該市の補聴器購入費助成ページ: 仙台市自身の「軽・中等度難聴児の補聴器購入等の助成」ページであり、別市・別区市ではない。(d)現行: 平成25年7月1日開始、受付終了の記載なし。(e)国/県制度の誤認なし: 仙台市の市独自制度。(f)対象の一部を全体としていない: 18歳未満・両耳30dB以上・手帳非該当・医師が必要と認める、という難聴児限定の範囲がタイトル/summary/targetPeoughで正しく限定されている。高齢者（加齢性難聴）向けの市独自助成は公式に確認できないとする注記も妥当。(g)複数制度の混在なし。(h)FORBIDDEN断定な' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='miyagi' and m.slug='sendai' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.saitama.lg.jp/kosodate/shiritai/category10/p103567.html', '敵対的検証を2026-06-27に実施。(a)到達: program.officialUrl をWebFetchで取得成功。(b)許可ホスト: www.city.saitama.lg.jp は .lg.jp の市公式ドメインで許可ホスト一致。(c)当該市・当該制度: 「軽・中等度難聴児の補聴器の交付」というさいたま市公式ページで別市・別区市ではない。(d)現行性: 古い年度・受付終了の記載なし。(e)国/県制度の誤認なし: 市独自の軽・中等度難聴児助成で補装具費支給(国制度)と別系統として正しく区別。(f)対象の一部を全体扱いしていない: 難聴児向け制度と明記し高齢者向けは別物として注記。(g)複数制度の混在なし: 難聴児助成1件のみをprogram化。(h)断定回避: 金額・所得・対象・必要書類・期限・電話番号をuncertainFieldsに格納し「公式で確認」を付し概括。追加検証: 西区支援課 048-620-2662 は公式記載と一致。WebSearchで加齢性難聴の高齢者向け市独自助成は現時点で未実施(議員団が新設要望の段階)と再確認。slug/prefectureSlug=' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='saitama' and m.slug='saitama' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-06-27', 'https://www.city.chiba.jp/hokenfukushi/koreishogai/korei/hocyoki.html', '敵対的検証完了。一次調査のcoverage=not_found_on_official_siteは妥当と確認。3つの公式ページをWebFetchで再検証した。\n\n【再検証結果（いずれも公式 city.chiba.jp ドメイン）】\n1. 高齢福祉「耳が聞こえにくいと思ったら（補聴器について）」(https://www.city.chiba.jp/hokenfukushi/koreishogai/korei/hocyoki.html、最終更新2026-03-30)＝経済的支援は (a)補装具費支給（聴覚障害6級以上の身体障害者手帳所持者・原則1割負担）と (b)医療費控除のみ。市独自の高齢者向け補聴器助成なし。問い合わせ=高齢福祉課 043-245-5166 / korei.HWS@city.chiba.lg.jp。\n2. 「高齢者への助成・支援制度」一覧 (https://www.city.chiba.jp/kenko/koresha/jose/index.html)＝長寿祝金・住宅改修費支援・ごみ出し支援等13制度を掲載するが補聴器助成は無し。\n3. FAQ 3159 (h' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='chiba' and m.slug='chiba' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.yokohama.lg.jp/kenko-iryo-fukushi/kenko-iryo/iryo/seisaku/hochokijosei.html', '敵対的検証完了。program.officialUrl（https://www.city.yokohama.lg.jp/kenko-iryo-fukushi/kenko-iryo/iryo/seisaku/hochokijosei.html）をWebFetchで再取得し、一次調査の内容を独立検証した。検証結果: (a)到達=ページはアクティブで受付中。(b)許可ホスト=www.city.yokohama.lg.jp は .lg.jp で許可ホスト一致。FAQ専用ドメインではない。(c)当該市の補聴器助成=「横浜市難聴者補聴器購入費助成事業」で横浜市（医療局医療政策課所管）の制度であることを確認。別市・別区市ではない。(d)現行年度=令和8年度（FY2026）、実施期間 令和8年6月22日〜令和9年2月26日（必着）。確認日2026-06-27時点で受付中・期限内。受付終了や旧年度ではない。(e)国/都道府県制度の誤認なし=横浜市独自事業と確認（身体障害者手帳・補装具費支給とは別枠の高齢者向け加齢性難聴支援）。(f)対象の一部を全体と記載していない=対象は50歳以上・市民税非課税世帯・両' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kanagawa' and m.slug='yokohama' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
