insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.sagamihara.kanagawa.jp/kosodate/1026646/kaigo/1025658.html', '敵対的検証完了。program.officialUrl（https://www.city.sagamihara.kanagawa.jp/kosodate/1026646/kaigo/1025658.html）をWebFetchで2回照合。(a)到達OK (b)ホストwww.city.sagamihara.kanagawa.jpは許可パターンcity.*に一致（FAQ専用ドメインでない） (c)相模原市自身の補聴器購入費助成ページであり別市・別区市でない (d)ページ更新日=令和7年5月7日で現行、受付終了の記載なし (e)国/都道府県制度ではなく相模原市独自の介護予防促進事業 (f)対象（65歳以上・市民税非課税・聴覚障害手帳非保持・医師の必要性証明・原則両耳30dB以上・本助成未受給）を一部のみで全体と誤認していない (g)別途存在する軽度・中等度難聴児向けの助成（障害分野）とは混ぜず、高齢者向け制度のみを記録 (h)断定なし・金額/所得/対象は概括＋公式確認の注記あり。検証で判明した精緻化点として、助成上限2万円（医療機器認定の補聴器本体購入費と上限額のいずれか低い額）、申請窓口=' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kanagawa' and m.slug='sagamihara' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
