insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.kyoto.lg.jp/hagukumi/page/0000229104.html', '一次URL(https://www.city.kyoto.lg.jp/hagukumi/page/0000229104.html)をWebFetchで検証＝到達OK。許可ホスト(city.kyoto.lg.jp＝.lg.jp)一致。ページタイトル「京都市難聴児補聴器購入費助成事業実施要綱」＝京都市(別市でない)の補聴器購入費助成そのものの当該市ページ。最新改正令和6年(2024)7月1日施行＝現行・受付終了でない。対象=身体障害者手帳の交付対象とならない18歳未満の難聴児(指定医が補聴器の必要性を認めた者)、助成額=補聴器1個4万円上限(価格が下回る場合はその価格)、5年未満の再助成不可、申請=申請書＋医師意見書＋事業者見積書を市長へ提出、所管=子ども若者はぐくみ局子ども家庭支援課(代表075-222-3939／発達支援担当075-222-3937)。所得制限の規定は実施要綱本文に記載なし。国/都道府県制度の誤認なし(難聴児向け市独自助成として正しく記述)、複数制度の混在なし、対象の一部を全体と書く誤りなし(高齢者・成人一般向け市独自助成は非確認である旨をdisclaimerで明示)。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kyoto' and m.slug='kyoto' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.osaka.lg.jp/fukushi/page/0000648793.html', '敵対的検証としてofficialUrl(0000648793.html)をWebFetchで直接再取得し、一次調査の全主張を一次資料と照合した。(a)到達OK。(b)許可ホスト=www.city.osaka.lg.jp（.lg.jp/city.*。FAQ専用ドメインでない）。(c)当該市=大阪市の「大阪市難聴高齢者補聴器購入費助成事業」案内ページで、別市・別区市ではない。(d)ページ作成日2025-04-01・令和7年4月以降適用・受付終了記載なし＝現行。(e)国/都道府県制度の一般説明でなく大阪市独自の高齢者向け（介護予防目的）市制度。(f)対象は高齢者(65歳以上)で正しく、障害児向けの軽度・中等度難聴児助成(0000117931)とは混同していない。(g)複数制度の混在なし＝単一制度。(h)FORBIDDEN/断定なし、金額(上限25,000円)・対象・手続きは「公式案内では」「とされています」「公式ページで確認」で概括し非断定。公式本文で確認した内容＝対象要件（申請時点で大阪市内住所の65歳以上／身体障がい者手帳(聴覚)の交付対象者でない／両耳それぞれ30dB以上70dB未満／' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='osaka' and m.slug='osaka' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-06-27', 'https://www.city.sakai.lg.jp/kenko/fukushikaigo/koreishafukushi/kaigoyobo/nanchou.html', '独立検証で一次調査の not_found_on_official_site を妥当と確認（確認日2026-06-27）。
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.kobe.lg.jp/a95295/kenko/handicap/zaitakufukushi/kigu/nanchojihochoki.html', '敵対的再検証(2026-06-27)。program.officialUrl をWebFetchで取得し全判定項目を確認。(a)到達=可、最終更新2025-10-23で現行。(b)許可ホスト=city.kobe.lg.jp（.lg.jp）で適合。(c)神戸市公式の「軽度・中等度難聴児補聴器購入費等助成事業」専用ページで、補聴器購入費助成そのもの。別市・別区市の誤りなし。(d)受付終了/旧年度でない。(e)国・都道府県制度の一般説明を市独自と誤認していない（神戸市の市独自事業）。(f)対象を「軽度・中等度難聴児（児童限定）」と正しく限定して記述しており、対象の一部を全体と書く誤りなし。(g)単一制度のみで複数混在なし。(h)FORBIDDEN/断定なし。公式文言と一次調査の整合を確認：年齢=18歳到達日以後最初の3/31まで、聴力=両耳30dB以上70dB未満、所得制限=2024-04-01撤廃、助成上限=ポケット型/耳かけ型40,000円・骨導式眼鏡型/オーダーメイド耳穴型/補聴システム100,000円、申請=各区役所（北須磨支所）保健福祉課。いずれも一致。高齢者（加齢性難聴）向け助成' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='hyogo' and m.slug='kobe' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.okayama.jp/kurashi/0000061124.html', '敵対的検証を実施。program.officialUrl（https://www.city.okayama.jp/kurashi/0000061124.html）をWebFetchで取得し本文を確認した。(a)到達OK。(b)ホストwww.city.okayama.jpは許可パターンcity.*に一致する岡山市公式。(c)当該ページは岡山市の「難聴高齢者補聴器購入費助成事業」そのもので、別市・別区市ではない。(d)最終更新2026-02-17、受付終了・廃止の記載なしで現行。(e)市独自事業で国・都道府県制度の誤認なし。(f)対象要件は一体の制度として正確に記載され、一部を全体と誤記していない。(g)障害福祉の補装具・難聴児助成（別ページ）と混在させていない。(h)金額・所得・聴力等は概括＋「公式で確認」で断定回避。一次調査はおおむね正確だったが、公式本文で確認できた追加情報として、対象要件に「過去5年以内に本事業の助成金交付決定を受けていない方」がある点をtargetPeopleに補い、担当係名を「在宅支援係」まで明示し、必要書類に「実績報告及び請求書兼委任状」を追記した。slug=' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='okayama' and m.slug='okayama' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.hiroshima.lg.jp/site/syougaijiritu01/18646.html', '敵対的検証完了。program.officialUrl（https://www.city.hiroshima.lg.jp/site/syougaijiritu01/18646.html）をWebFetchで取得し全項目を一次資料と照合。(a)到達OK。(b)許可ホスト=www.city.hiroshima.lg.jp（.lg.jp）合格。(c)広島市自身の「難聴児補聴器購入費助成事業」ページで当該市の補聴器購入費助成に該当（別市・別区市でない）。(d)現行制度（最終更新2026-03-31、令和8年4月から代理受領方式へ変更予定の現行案内）で受付終了ではない。(e)国制度の「補装具費支給」を市独自と誤認していない（市独自の軽度・中等度難聴児向け助成を正しく抽出、補装具は参照扱いのみ）。(f)対象の一部を全体と書いていない（難聴児18歳未満に限定した制度であることをtitle/summary/targetPeopleで明示、高齢者向けは未確認とuncertainFieldsに分離）。(g)複数制度を1件に混在させていない（難聴児助成1件のみをprogram化、補装具費支給は本文の注記参照' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='hiroshima' and m.slug='hiroshima' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-06-27', 'https://www.city.kitakyushu.lg.jp/contents/175_00001.html', '検証の結果、一次調査の coverage=not_found_on_official_site は妥当と確認した（確認日 2026-06-27）。複数の独立した敵対的チェックがすべて「北九州市独自の高齢者向け／加齢性難聴向け補聴器購入費助成は公式サイト上に確認できない」を裏付けた。
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.fukuoka.lg.jp/fukushi/syougaisyashien/health/documents/nanntyoujiosirase.pdf', '敵対的検証完了。officialUrl(https://www.city.fukuoka.lg.jp/fukushi/syougaisyashien/health/nitijyoseikatuyougu.html)とevidenceUrl(難聴児osirase.pdf)の両方をWebFetch/直接読込で検証。(a)両URL到達 (b)ホストはcity.fukuoka.lg.jp＝.lg.jpで許可 (c)福岡市の難聴児補聴器購入助成そのもののページ・別市別区でない (d)HTMLページ更新日2025-04-01・受付終了記載なし＝現行 (e)国の補装具費制度ではなく福岡市独自の市制度（手帳対象外児童向け）として正しく分類 (f)対象を全体と誤記していない (g)補装具費制度や加齢性難聴と混同せず1制度に限定 (h)金額・対象は概括＋公式確認を維持。
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-27', 'https://www.city.kumamoto.jp/kiji00370685/index.html', 'WebFetchで熊本市公式ページ(www.city.kumamoto.jp/kiji00370685、許可ホストcity.*)を検証。(a)到達OK (b)許可ホスト一致 (c)「熊本市難聴高齢者介護予防促進事業（高齢者補聴器購入費助成）」で当該市の自前事業（別市・別区でない） (d)最終更新2026-06-18・受付開始令和8年6月1日で現行・受付終了でない (e)国/県制度の誤認なし＝市の介護予防促進事業 (f)対象（65歳以上・市民税非課税世帯または生活保護受給・身体障害者手帳〔聴覚〕対象外）を正しく記載 (g)単一制度 (h)助成額はページに一切記載がなく断定なし・uncertainFieldsで明示・「公式で確認」のヘッジあり。問い合わせ先096-334-1500（熊本市コールセンター）はページに実在。slug/prefecture/municipality識別子も正。是正不要。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='kumamoto' and m.slug='kumamoto' and t.slug='hearing-aid' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
